2286 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2287 |     function applyLocalPatch(content, ops) {
2288 |         let lines = content.split('\n');
2289 |         let logs = [];
2290 |         let success = true;
2291 | 
2292 |         if (typeof ops === 'string') {
2293 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2294 |         }
2295 | 
2296 |         ops.forEach(op => {
2297 |             if (op.action === 'comment') return;
2298 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2299 |             
2300 |             if (op.action === 'replace_block') {
2301 |                 // Strategy 1: Exact String Match (Fastest)
2302 |                 const currentStr = lines.join('\n');
2303 |                 if (currentStr.includes(op.find_block)) {
2304 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2305 |                     logs.push('Exact match applied');
2306 |                     return;
2307 |                 }
2308 | 
2309 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2310 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2311 |                 if (searchLines.length === 0) return;
2312 | 
2313 |                 let matchStart = -1;
2314 |                 let matchEnd = -1;
2315 | 
2316 |                 // Scan file lines
2317 |                 for (let i = 0; i < lines.length; i++) {
2318 |                     // If first line matches (ignoring whitespace)
2319 |                     if (lines[i].trim() === searchLines[0]) {
2320 |                         // Check subsequent lines
2321 |                         let allMatch = true;
2322 |                         let fileOffset = 0;
2323 |                         let searchOffset = 1;
2324 |                         
2325 |                         while (searchOffset < searchLines.length) {
2326 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2327 |                             const nextFile = lines[i + fileOffset + 1].trim();
2328 |                             // Skip empty lines in file if they aren't in search block
2329 |                             if (nextFile === '') {
2330 |                                 fileOffset++;
2331 |                                 continue;
2332 |                             }
2333 |                             if (nextFile !== searchLines[searchOffset]) {
2334 |                                 allMatch = false;
2335 |                                 break;
2336 |                             }
2337 |                             fileOffset++;
2338 |                             searchOffset++;
2339 |                         }
2340 | 
2341 |                         if (allMatch) {
2342 |                             matchStart = i;
2343 |                             matchEnd = i + fileOffset;
2344 |                             break;
2345 |                         }
2346 |                     }
2347 |                 }
2348 | 
2349 |                 if (matchStart !== -1) {
2350 |                     // Replace the range of lines
2351 |                     const replacement = op.replace_with.split('\n');
2352 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2353 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2354 |                 } else {
2355 |                     success = false;
2356 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2357 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2358 |                 }
2359 |             }
2360 |         });
2361 |         return { content: lines.join('\n'), success, logs };
2362 |     }
