5190 |     function formatBytes(bytes) {
5191 |         if (!bytes) return '0 B';
5192 |         const k = 1024;
5193 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5194 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5195 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5196 |     }
