5198 |     function timeAgo(dateString) {
5199 |         const date = new Date(dateString);
5200 |         const now = new Date();
5201 |         const seconds = Math.floor((now - date) / 1000);
5202 |         if (seconds < 10) return 'just now';
5203 |         if (seconds < 60) return seconds + 's ago';
5204 |         const minutes = Math.floor(seconds / 60);
5205 |         if (minutes < 60) return minutes + 'm ago';
5206 |         const hours = Math.floor(minutes / 60);
5207 |         if (hours < 24) return hours + 'h ago';
5208 |         return date.toLocaleDateString();
5209 |     }
