7921 |     function extractTableNames(sql) {
7922 |         if (!sql) return [];
7923 |         const tables = [];
7924 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7925 |         
7926 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7927 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7928 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7929 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7930 | 
7931 |         let match;
7932 |         while ((match = fromRegex.exec(sql)) !== null) {
7933 |             const name = match[1];
7934 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7935 |                 tables.push(name);
7936 |             }
7937 |         }
7938 |         
7939 |         while ((match = metaRegex.exec(sql)) !== null) {
7940 |             const name = match[1];
7941 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7942 |                 tables.push(name);
7943 |             }
7944 |         }
7945 | 
7946 |         return tables;
7947 |     }
7948 | 
7949 |     function convertToCSV(resultObj) {
7950 |         const data = resultObj.data || [];
7951 |         if (!data.length) return '';
7952 |         
7953 |         const tables = extractTableNames(resultObj.sql);
7954 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7955 | 
7956 |         const headers = Object.keys(data[0]);
7957 |         const rows = data.map(row => 
7958 |             headers.map(header => {
7959 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7960 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7961 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7962 |             }).join(',')
7963 |         );
7964 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7965 |     }
