2058 |     function smartJSONParse(str) {
2059 |         // The Necromancer: Schema-Aware Reconstruction
2060 |         if (!str) return null;
2061 |         
2062 |         let raw = str.trim();
2063 |         
2064 |         // 1. Extract only the JSON part (ignore AI chatter)
2065 |         const firstBracket = raw.indexOf('[');
2066 |         const lastBracket = raw.lastIndexOf(']');
2067 |         if (firstBracket !== -1 && lastBracket !== -1) {
2068 |             raw = raw.substring(firstBracket, lastBracket + 1);
2069 |         }
2070 | 
2071 |         // 2. Kill trailing commas in arrays/objects
2072 |         raw = raw.replace(/,[\s\r\n]*([\}\]])/g, '$1');
2073 | 
2074 |         // 3. Handle truncated JSON (AI cut off)
2075 |         let openBrackets = (raw.match(/\[/g) || []).length;
2076 |         let closeBrackets = (raw.match(/\]/g) || []).length;
2077 |         while (openBrackets > closeBrackets) { raw += ']'; closeBrackets++; }
2078 |         
2079 |         let openBraces = (raw.match(/\{/g) || []).length;
2080 |         let closeBraces = (raw.match(/\}/g) || []).length;
2081 |         while (openBraces > closeBraces) { raw += '}'; closeBraces++; }
2082 | 
2083 |         // 4. THE MASTER FIX: Structural String Sanitization
2084 |         // We identify fields likely to contain code and protect them
2085 |         const codeFields = ['find_block', 'replace_with', 'content', 'text', 'explanation'];
2086 |         
2087 |         let processed = '';
2088 |         let inString = false;
2089 |         let currentField = '';
2090 |         let escapeNext = false;
2091 | 
2092 |         for (let i = 0; i < raw.length; i++) {
2093 |             let char = raw[i];
2094 | 
2095 |             if (char === '"' && !escapeNext) {
2096 |                 inString = !inString;
2097 |                 processed += char;
2098 |                 continue;
2099 |             }
2100 | 
2101 |             if (inString) {
2102 |                 if (char === '\\') {
2103 |                     // If it's a standalone backslash not part of a known escape, double it
2104 |                     const next = raw[i+1];
