2380 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2381 |     function applyLocalPatch(content, ops) {
2382 |         let lines = content.split('\n');
2383 |         let logs = [];
2384 |         let success = true;
2385 | 
2386 |         if (typeof ops === 'string') {
2387 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2388 |         }
2389 | 
2390 |         ops.forEach(op => {
2391 |             if (op.action === 'comment') return;
2392 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2393 |             
2394 |             if (op.action === 'replace_block') {
2395 |                 // Strategy 1: Exact String Match (Fastest)
2396 |                 const currentStr = lines.join('\n');
2397 |                 if (currentStr.includes(op.find_block)) {
2398 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2399 |                     logs.push('Exact match applied');
2400 |                     return;
2401 |                 }
2402 | 
2403 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2404 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2405 |                 if (searchLines.length === 0) return;
2406 | 
2407 |                 let matchStart = -1;
2408 |                 let matchEnd = -1;
2409 | 
2410 |                 // Scan file lines
2411 |                 for (let i = 0; i < lines.length; i++) {
2412 |                     // If first line matches (ignoring whitespace)
2413 |                     if (lines[i].trim() === searchLines[0]) {
2414 |                         // Check subsequent lines
2415 |                         let allMatch = true;
2416 |                         let fileOffset = 0;
2417 |                         let searchOffset = 1;
2418 |                         
2419 |                         while (searchOffset < searchLines.length) {
2420 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2421 |                             const nextFile = lines[i + fileOffset + 1].trim();
2422 |                             // Skip empty lines in file if they aren't in search block
2423 |                             if (nextFile === '') {
2424 |                                 fileOffset++;
2425 |                                 continue;
2426 |                             }
2427 |                             if (nextFile !== searchLines[searchOffset]) {
2428 |                                 allMatch = false;
2429 |                                 break;
2430 |                             }
2431 |                             fileOffset++;
2432 |                             searchOffset++;
2433 |                         }
2434 | 
2435 |                         if (allMatch) {
2436 |                             matchStart = i;
2437 |                             matchEnd = i + fileOffset;
2438 |                             break;
2439 |                         }
2440 |                     }
2441 |                 }
2442 | 
2443 |                 if (matchStart !== -1) {
2444 |                     // Replace the range of lines
2445 |                     const replacement = op.replace_with.split('\n');
2446 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2447 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2448 |                 } else {
2449 |                     success = false;
2450 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2451 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2452 |                 }
2453 |             }
2454 |         });
2455 |         return { content: lines.join('\n'), success, logs };
2456 |     }
