5284 |     function formatBytes(bytes) {
5285 |         if (!bytes) return '0 B';
5286 |         const k = 1024;
5287 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5288 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5289 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5290 |     }
