5292 |     function timeAgo(dateString) {
5293 |         const date = new Date(dateString);
5294 |         const now = new Date();
5295 |         const seconds = Math.floor((now - date) / 1000);
5296 |         if (seconds < 10) return 'just now';
5297 |         if (seconds < 60) return seconds + 's ago';
5298 |         const minutes = Math.floor(seconds / 60);
5299 |         if (minutes < 60) return minutes + 'm ago';
5300 |         const hours = Math.floor(minutes / 60);
5301 |         if (hours < 24) return hours + 'h ago';
5302 |         return date.toLocaleDateString();
5303 |     }
