8015 |     function extractTableNames(sql) {
8016 |         if (!sql) return [];
8017 |         const tables = [];
8018 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8019 |         
8020 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8021 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8022 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8023 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8024 | 
8025 |         let match;
8026 |         while ((match = fromRegex.exec(sql)) !== null) {
8027 |             const name = match[1];
8028 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8029 |                 tables.push(name);
8030 |             }
8031 |         }
8032 |         
8033 |         while ((match = metaRegex.exec(sql)) !== null) {
8034 |             const name = match[1];
8035 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8036 |                 tables.push(name);
8037 |             }
8038 |         }
8039 | 
8040 |         return tables;
8041 |     }
8042 | 
8043 |     function convertToCSV(resultObj) {
8044 |         const data = resultObj.data || [];
8045 |         if (!data.length) return '';
8046 |         
8047 |         const tables = extractTableNames(resultObj.sql);
8048 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8049 | 
8050 |         const headers = Object.keys(data[0]);
8051 |         const rows = data.map(row => 
8052 |             headers.map(header => {
8053 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8054 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8055 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8056 |             }).join(',')
8057 |         );
8058 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8059 |     }
