        .hidden { display: none !important; }
        .flex-between { display: flex; justify-content: space-between; align-items: center; }
        .flex-gap { display: flex; gap: 8px; }

        /* MAIN VIEW LAYOUT */
        .main-view {
            flex: 1; overflow-y: auto; padding: 20px;
            padding-top: calc(env(safe-area-inset-top, 0px) + 20px);
            padding-bottom: calc(var(--nav-height) + 40px);
            scrollbar-width: none;
            scroll-behavior: smooth;
            -webkit-overflow-scrolling: touch;
        }
        /* Safe space for the bottom navigation and FAB */
        .bottom-spacer {
            height: calc(var(--nav-height) + 100px);
            width: 100%;
            flex-shrink: 0;
        }
        .main-view::-webkit-scrollbar { display: none; }

        .tab-content { display: none; animation: fadeUp 0.2s ease-out; }
        .tab-content.active { display: block; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }

        .header { font-size: 24px; font-weight: 700; margin-bottom: 20px; display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; }

        .card {
            background: var(--card-bg); border: 1px solid var(--border);
            border-radius: 16px; padding: 16px; margin-bottom: 16px;
        }

        /* BUTTONS */
        .btn {
            width: 100%; padding: 14px; border-radius: 12px; border: none;
            font-weight: 600; font-size: 15px; cursor: pointer;
            display: flex; align-items: center; justify-content: center; gap: 8px;
            color: white; transition: opacity 0.2s;
        }
        .btn:active { opacity: 0.7; }
        .btn-primary { background: var(--primary); }
        .btn-dev { background: var(--dev); color: black; }
        .btn-prod { background: var(--prod); }
        .btn-danger { background: var(--danger); }
        .btn-outline { background: transparent; border: 1px solid var(--border); color: var(--text-muted); }

        /* INPUTS */
        .input-group { margin-bottom: 16px; }
        .input-label { display: block; color: var(--text-muted); font-size: 11px; margin-bottom: 6px; text-transform: uppercase; letter-spacing: 0.5px; }
        .input-field {
            width: 100%; background: var(--input-bg); border: 1px solid var(--border);
            color: var(--text-main); padding: 12px; border-radius: 10px;
            font-family: 'JetBrains Mono', monospace; font-size: 13px;
        }
        .input-field:focus { outline: 2px solid var(--primary); border-color: transparent; }

        /* FILE LIST */
        .file-list { display: flex; flex-direction: column; gap: 0; }
        .file-item {
            display: flex; justify-content: space-between; align-items: center;
            padding: 12px; border-bottom: 1px solid var(--border);
        }
        .file-item:last-child { border-bottom: none; }

        /* VERSIONS / HISTORY */
        .version-item { position: relative; padding: 12px 0; border-bottom: 1px solid var(--border); }
        .version-item:last-child { border-bottom: none; }
        .v-header { display: flex; justify-content: space-between; align-items: flex-start; }
