            border-left: 2px solid var(--primary); display: none; cursor: pointer;
        }
        .v-note.has-content { display: block; }

        /* INSPECTOR STYLES */
        .ins-row { padding: 8px 12px; border-bottom: 1px solid #1a1a1c; font-family: 'JetBrains Mono'; font-size: 11px; position: relative; animation: fadeUp 0.1s; display: flex; align-items: flex-start; }
.ins-row details summary::-webkit-details-marker { color: var(--ai-accent); margin-top: 3px; }
.ins-row details[open] summary { border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 4px; margin-bottom: 4px; }
        .ins-row:hover .ins-copy-btn { opacity: 1; }
        .ins-copy-btn { position: absolute; right: 8px; top: 8px; opacity: 0; background: #222; border: 1px solid #444; color: #888; padding: 2px 6px; border-radius: 4px; cursor: pointer; z-index: 10; }
